import { Kafka } from 'kafkajs'

const kafka = new Kafka({ brokers: ['{HOST}:{PORT}'] })
const producer = kafka.producer()
await producer.connect()
await producer.send({ topic: '{RESOURCE_NAME}', messages: [{ value: JSON.stringify({ workspaceId: '{WORKSPACE_ID}' }) }] })

import { Kafka } from 'kafkajs'

const kafka = new Kafka({ brokers: ['{HOST}:{PORT}'] })
const consumer = kafka.consumer({ groupId: 'workspace-{WORKSPACE_ID}' })
await consumer.connect()
await consumer.subscribe({ topic: '{RESOURCE_NAME}' })
